import { motion } from 'framer-motion';
import Icon from './Icon';
export default function ProductCard({ product, onSelect }) { return <motion.article layout whileHover={{ y:-6 }} onClick={()=>onSelect(product)} className="cursor-pointer bg-[#282d28] text-[#f4f3ec]"><div className={`relative flex h-[210px] items-center justify-center overflow-hidden ${product.image?'bg-[#d9ddd1]':'bg-gradient-to-br from-[#d8ddd0] to-[#adb7a3] text-[#566056]'}`}>{product.image?<img src={`/assets/${product.image}`} alt={product.model} className="h-full w-full object-cover mix-blend-multiply"/>:<><span className="text-6xl opacity-50">◒</span><span className="absolute bottom-5 font-mono text-[10px] tracking-[2px]">BERCA MP</span></>}<span className="absolute right-3 top-3 bg-[#f1f2e9] px-2 py-1 font-mono text-[9px] text-[#4c5148]">{product.brand}</span></div><div className="p-5"><p className="font-mono text-[9px] uppercase text-[#9ba393]">{product.category}</p><h3 className="mt-2 text-2xl tracking-[-.04em]">{product.model}</h3><ul className="my-4 min-h-[93px] space-y-1 border-b border-[#464d44] pb-4">{product.specs.slice(0,3).map(spec=><li key={spec} className="text-[10px] leading-5 text-[#bec6b8] before:mr-2 before:text-[#d8f35a] before:content-['+']">{spec}</li>)}</ul><span className="flex items-center justify-between text-[10px] font-bold text-[#d8f35a]">Lihat detail <Icon name="arrow" size={14}/></span></div></motion.article> }
