import { motion } from 'framer-motion';
import Icon from './Icon';
import Reveal from './Reveal';
const symbols = { Excavator:'▱', 'Wheel Loader':'◒', 'Motor Grader':'╱', Bulldozer:'▰', 'Road Roller':'◉', 'Electric Series':'ϟ' };
export default function CategoryRail({ categories, active, onPick }) { return <section className="border-b border-black/10 px-6 py-20 md:px-[10vw] md:py-24"><Reveal><div className="mb-12 flex flex-col justify-between gap-7 md:flex-row md:items-end"><div><p className="font-mono text-[10px] tracking-[1.2px] text-[#777a71]">PILIH SESUAI KEBUTUHAN</p><h2 className="mt-5 text-6xl font-bold leading-[.9] tracking-[-.07em]">Built for the<br/><em className="text-[#858981] not-italic">big picture.</em></h2></div><p className="max-w-[260px] text-xs leading-7 text-[#70736c]">Dari pembukaan lahan hingga finishing jalan, setiap unit dipilih untuk menghadirkan performa yang dapat diandalkan.</p></div></Reveal><div className="grid grid-cols-1 gap-px border border-black/10 bg-black/10 sm:grid-cols-2 lg:grid-cols-3">{categories.map((category,index)=><motion.button whileHover={{ scale:1.015 }} key={category.name} onClick={()=>onPick(category.name)} className={`flex min-h-[130px] items-center gap-4 px-6 text-left transition ${active===category.name?'bg-[#d8f35a]':'bg-[#f2f1eb] hover:bg-[#d8f35a]'}`}><span className="w-10 text-3xl">{symbols[category.name]}</span><span className="flex flex-1 flex-col gap-1.5"><b className="text-sm">{category.name}</b><small className="font-mono text-[10px] text-[#7d8178]">{category.count} model</small></span><Icon name="arrow" size={16} /></motion.button>)}</div></section> }
