import { useMemo, useState } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import ProductCard from './ProductCard';
import Reveal from './Reveal';
export default function Catalog({ products, onSelect, onReset }) { const [sort,setSort]=useState('featured'); const sorted=useMemo(()=>[...products].sort((a,b)=>sort==='az'?a.model.localeCompare(b.model):sort==='za'?b.model.localeCompare(a.model):a.id-b.id),[products,sort]); return <section id="catalog" className="border-b border-[#434940] bg-[#1c201c] px-6 py-20 text-[#f4f3ec] md:px-[10vw] md:py-24"><Reveal><div className="mb-14 flex flex-col justify-between gap-7 md:flex-row md:items-end"><div><p className="font-mono text-[10px] tracking-[1.2px] text-[#91988b]">KOLEKSI MESIN</p><h2 className="mt-5 text-6xl font-bold leading-[.9] tracking-[-.07em]">Find your<br/><em className="text-[#90968b] not-italic">workhorse.</em></h2></div><div className="flex items-center justify-between gap-6 font-mono text-[10px] text-[#aeb4a8]"><span>{products.length} dari 40 model</span><select value={sort} onChange={event=>setSort(event.target.value)} className="border border-[#50564d] bg-transparent px-3 py-2.5 text-[#f4f3ec] outline-none"><option className="text-black" value="featured">Urutkan: Pilihan</option><option className="text-black" value="az">Nama A–Z</option><option className="text-black" value="za">Nama Z–A</option></select></div></div></Reveal><AnimatePresence mode="popLayout">{sorted.length?<motion.div layout className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">{sorted.map(product=><ProductCard key={product.id} product={product} onSelect={onSelect}/>)}</motion.div>:<div className="py-16 text-center"><p className="mb-5 text-lg">Model tidak ditemukan.</p><button onClick={onReset} className="bg-[#d8f35a] px-4 py-3 text-[11px] font-bold text-[#171a17]">Reset filter</button></div>}</AnimatePresence></section> }
