import { AnimatePresence, motion } from 'framer-motion';
import Icon from './Icon';
export default function DetailModal({ product, onClose }) { return <AnimatePresence>{product&&<motion.div initial={{opacity:0}} animate={{opacity:1}} exit={{opacity:0}} onClick={onClose} className="fixed inset-0 z-50 grid place-items-center bg-[#111a] p-5"><motion.div initial={{scale:.94,y:20}} animate={{scale:1,y:0}} exit={{scale:.94,y:20}} onClick={event=>event.stopPropagation()} className="relative grid w-full max-w-3xl overflow-hidden bg-[#f2f1eb] md:grid-cols-[45%_55%]"><button onClick={onClose} aria-label="Tutup" className="absolute right-4 top-4 z-10 rounded-full p-2"><Icon name="close"/></button><div className="grid min-h-[250px] place-items-center overflow-hidden bg-[#cdd4c3] md:min-h-[420px]">{product.image?<img src={`/assets/${product.image}`} alt={product.model} className="h-full w-full object-cover mix-blend-multiply"/>:<span className="font-mono text-xs text-[#5c6757]">{product.category}</span>}</div><div className="p-7 md:p-12"><p className="font-mono text-[10px] tracking-[1.2px] text-[#777a71]">{product.brand} / {product.category}</p><h2 className="mt-5 text-5xl font-bold tracking-[-.07em]">{product.model}</h2><p className="mt-5 text-xs leading-6 text-[#70736c]">Unit pilihan untuk kebutuhan proyek Anda. Dapatkan informasi lengkap dan rekomendasi dari tim Berca Mandiri Perkasa.</p><div className="my-6 flex flex-wrap gap-2">{product.specs.map(spec=><span key={spec} className="border border-black/15 px-2.5 py-2 font-mono text-[10px]">{spec}</span>)}</div><a href={product.url} target="_blank" rel="noreferrer" className="inline-flex items-center gap-4 bg-[#d8f35a] px-4 py-3 text-[10px] font-bold">Buka spesifikasi resmi <Icon name="external" size={15}/></a></div></motion.div></motion.div>}</AnimatePresence> }
